-- Rebuild tareas schema around the event block/task catalog generated from CSV exports.
create schema if not exists tareas;
create extension if not exists pgcrypto with schema extensions;

drop function if exists public.list_timeline_events();
drop function if exists public.get_timeline_event(uuid);
drop function if exists public.save_timeline_snapshot(jsonb);
drop function if exists public.delete_timeline_event(uuid);
drop function if exists public.mark_timeline_assumption_reviewed(uuid, text, boolean);
drop function if exists public.get_event_catalog(integer);
drop view if exists public.event_catalog_tasks;
drop view if exists public.event_catalog_blocks;

do $$
declare
  r record;
begin
  for r in
    select tablename
    from pg_tables
    where schemaname = 'tareas'
  loop
    execute format('drop table if exists tareas.%I cascade', r.tablename);
  end loop;
end $$;

create table tareas.event_blocks (
  block_id text primary key,
  block_sort text not null,
  sort_order numeric,
  macrofase text,
  block_name text not null,
  "references" text,
  moments text,
  block_type text,
  turno_sugerido text,
  rol_principal text,
  min_personas_bloque text,
  staff_min integer,
  staff_max integer,
  regla_dotacion text,
  continuidad_dependencia text,
  hito_relevo text,
  num_tareas_camareros integer,
  rango_codigos_camareros text,
  codigos_camareros_lista text,
  task_codes jsonb not null default '[]'::jsonb,
  codigos_relacionados_otros_roles text,
  notas_operativas text,
  duracion_referencia_min integer,
  observacion_acta text,
  over_200_adjustment text,
  over_200_waiter_codes jsonb not null default '[]'::jsonb,
  over_200_other_role_codes jsonb not null default '[]'::jsonb,
  over_200_notes text,
  over_200_duration_reference_min integer,
  over_200_observacion_acta text,
  over_200_non_task_adjustments jsonb not null default '[]'::jsonb,
  raw jsonb not null default '{}'::jsonb,
  over_200_raw jsonb,
  created_at timestamptz not null default timezone('utc', now())
);

create table tareas.event_tasks (
  task_code text primary key,
  block_id text not null references tareas.event_blocks (block_id) on delete cascade,
  task_sort integer,
  referencia text,
  momento text,
  responsable text,
  task_name text not null,
  num_personas text,
  staff_min integer,
  staff_max integer,
  dependency_code text,
  details text,
  time_min_min integer,
  time_max_min integer,
  observaciones text,
  macrofase text,
  tipo_bloque text,
  turno text,
  over_200_affected boolean not null default false,
  over_200_scope text,
  over_200_adjustment text,
  over_200_notes text,
  raw jsonb not null default '{}'::jsonb,
  over_200_raw jsonb,
  created_at timestamptz not null default timezone('utc', now())
);

create index event_blocks_sort_idx on tareas.event_blocks (sort_order, block_sort, block_id);
create index event_blocks_reference_idx on tareas.event_blocks ("references", moments);
create index event_tasks_block_sort_idx on tareas.event_tasks (block_id, task_sort, task_code);
create index event_tasks_reference_idx on tareas.event_tasks (referencia, momento);

